a[href] {
  color: blue;
  text-decoration: underline;
}

a[title] {
  font-weight: bold;
  text-decoration: none;
}

a[href][title] {
  color: green;
}

a[class~="primary"] {
  color: red;
  font-weight: bold;
}

a[href^="https://"] {
  color: green;
  text-decoration: underline;
}

a[href$=".jpg"] {
  color: darkgreen;
  text-decoration: underline dotted;
}

a[href*="https"] {
  color: teal;
}

p[lang="en"] {
  font-style: italic;
}

div[data-lang="fr"] {
  color: blue;
}

/*Example targeting uppercase alphabetical numbering*/
ol[type="A"] {
  color: purple;
  font-weight: bold;
}

/*Example targeting lowercase Roman numerals*/
ol[type="i"] {
  color: green;
}
